4	
5	// Direction arrays matching game Direction enum order: UP, LEFT, DOWN, RIGHT
6	static const int AI_DR[4] = {-1, 0, 1, 0};
7	static const int AI_DC[4] = {0, -1, 0, 1};
8	static const Direction AI_DIR[4] = {UP, LEFT, DOWN, RIGHT};
9	
10	// BFS distance array
11	static int dist[MAX_MAP_SIZE][MAX_MAP_SIZE];
12	
13	// BFS queue
14	typedef struct node
15	{
16	    int r, c;
17	} Node;
18	static Node q[MAX_SNAKE_LEN];
19	
20	// ---------------------------------------------------------------------------
21	// Shared helpers
22	// ---------------------------------------------------------------------------
23	
24	// Check if a cell is passable for the AI (empty or food only)
25	static bool ai_can_go(const GameState *game, int r, int c)
26	{
27	    if (r <= 0 || r >= game->map_size - 1 || c <= 0 || c >= game->map_size - 1)
28	        return false;
29	    char ch = game->map[r][c];
30	    return (ch == '.' || ch == 'F');
31	}
32	
33	// BFS from food to compute distance grid
34	static void ai_bfs_from_food(const GameState *game, int fr, int fc)
35	{
36	    for (int r = 0; r < game->map_size; r++)
37	        for (int c = 0; c < game->map_size; c++)
38	            dist[r][c] = -1;
39	
40	    int front = 0, back = 0;
41	    q[back++] = {fr, fc};
42	    dist[fr][fc] = 0;
43	
44	    while (front < back)
45	    {
46	        Node cur = q[front++];
47	        for (int d = 0; d < 4; d++)
48	        {
49	            int nr = cur.r + AI_DR[d];
50	            int nc = cur.c + AI_DC[d];
51	            if (!ai_can_go(game, nr, nc))
52	                continue;
53	            if (dist[nr][nc] != -1)
54	                continue;
55	            dist[nr][nc] = dist[cur.r][cur.c] + 1;
56	            q[back++] = {nr, nc};
57	        }
58	    }
59	}
