61	// BFS to count free cells reachable from a starting point
62	static int ai_free_count(const GameState *game, int sr, int sc)
63	{
64	    int vis[MAX_MAP_SIZE][MAX_MAP_SIZE];
65	    memset(vis, 0, sizeof(vis));
66	
67	    Point queue[MAX_SNAKE_LEN];
68	    int front = 0, back = 0;
69	    queue[back++] = {sr, sc};
70	    vis[sr][sc] = 1;
71	    int cnt = 0;
72	
73	    while (front < back)
74	    {
75	        Point cur = queue[front++];
76	        cnt++;
77	        for (int d = 0; d < 4; d++)
78	        {
79	            int nr = cur.row + AI_DR[d];
80	            int nc = cur.col + AI_DC[d];
81	            if (nr <= 0 || nr >= game->map_size - 1 || nc <= 0 || nc >= game->map_size - 1)
82	                continue;
83	            if (vis[nr][nc])
84	                continue;
85	            char ch = game->map[nr][nc];
86	            if (ch != '.' && ch != 'F')
87	                continue;
88	            vis[nr][nc] = 1;
89	            queue[back++] = {nr, nc};
90	        }
91	    }
92	    return cnt;
93	}
