95	// BFS path finding on a simulated grid
96	static bool ai_bfs_path(char sim[MAX_MAP_SIZE][MAX_MAP_SIZE], int map_size,
97	                         int sr, int sc, int tr, int tc, int prev_dir[MAX_MAP_SIZE][MAX_MAP_SIZE])
98	{
99	    int vis[MAX_MAP_SIZE][MAX_MAP_SIZE];
100	    memset(vis, 0, sizeof(vis));
101	
102	    Point queue[MAX_SNAKE_LEN];
103	    int front = 0, back = 0;
104	    queue[back++] = {sr, sc};
105	    vis[sr][sc] = 1;
106	
107	    while (front < back)
108	    {
109	        Point cur = queue[front++];
110	        if (cur.row == tr && cur.col == tc)
111	            return true;
112	
113	        for (int d = 0; d < 4; d++)
114	        {
115	            int nr = cur.row + AI_DR[d];
116	            int nc = cur.col + AI_DC[d];
117	            if (nr <= 0 || nr >= map_size - 1 || nc <= 0 || nc >= map_size - 1)
118	                continue;
119	            if (vis[nr][nc])
120	                continue;
121	            if (nr == tr && nc == tc)
122	            {
123	                vis[nr][nc] = 1;
124	                prev_dir[nr][nc] = d;
125	                queue[back++] = {nr, nc};
126	                continue;
127	            }
128	            char ch = sim[nr][nc];
129	            if (ch != '.' && ch != 'F')
130	                continue;
131	            vis[nr][nc] = 1;
132	            prev_dir[nr][nc] = d;
133	            queue[back++] = {nr, nc};
134	        }
135	    }
136	    return false;
137	}
