139	// Check if AI can still reach its own tail after moving in direction d
140	static bool ai_can_reach_tail_after_move(const GameState *game, int d)
141	{
142	    const Point *body = game->ai_snake;
143	    int len = game->ai_length;
144	
145	    Point hd = body[0];
146	    Point tail = body[len - 1];
147	
148	    int nr = hd.row + AI_DR[d];
149	    int nc = hd.col + AI_DC[d];
150	
151	    char sim[MAX_MAP_SIZE][MAX_MAP_SIZE];
152	    for (int r = 0; r < game->map_size; r++)
153	        for (int c = 0; c < game->map_size; c++)
154	            sim[r][c] = game->map[r][c];
155	
156	    bool eat = (sim[nr][nc] == 'F');
157	    bool auto_grow = ((game->move_count + 1) % game->grow_step) == 0;
158	    bool will_grow = eat || auto_grow;
159	
160	    if (!will_grow)
161	        sim[tail.row][tail.col] = '.';
162	
163	    sim[hd.row][hd.col] = 'C';
164	    sim[nr][nc] = 'A';
165	
166	    int prev_dir[MAX_MAP_SIZE][MAX_MAP_SIZE];
167	    memset(prev_dir, -1, sizeof(prev_dir));
168	
169	    Point new_tail;
170	    if (will_grow)
171	        new_tail = tail;
172	    else
173	        new_tail = body[len - 2];
174	
175	    return ai_bfs_path(sim, game->map_size, nr, nc, new_tail.row, new_tail.col, prev_dir);
176	}
