178	// Collect all valid directions from the AI's current head position
179	static int collect_valid_dirs(const GameState *game, int *dirs_out)
180	{
181	    Point hd = game->ai_snake[0];
182	    int count = 0;
183	    for (int d = 0; d < 4; d++)
184	    {
185	        int nr = hd.row + AI_DR[d];
186	        int nc = hd.col + AI_DC[d];
187	        if (ai_can_go(game, nr, nc))
188	            dirs_out[count++] = d;
189	    }
190	    return count;
191	}
