414	                if (ch != '.')
415	                {
416	                    ok = false;
417	                    break;
418	                }
419	            }
420	            if (ok)
421	                placed = true;
422	        }
423	    }
424	
425	    if (!placed)
426	    {
427	        // Fallback: just place a 1-cell snake
428	        start = cells[rand() % count];
429	    }
430	
431	    // Place new AI snake, heading UP
432	    int len = placed ? 3 : 1;
433	    for (int i = 0; i < len; i++)
434	    {
435	        game->ai_snake[i] = {start.row + (len - 1 - i), start.col};
436	    }
437	    game->ai_length = len;
438	    game->ai_direction = UP;
439	    game->ai_is_alive = true;
440	    game->ai_score = 0;
441	    game->ai_food_eaten = 0;
442	    game->ai_pending_growth = 0;
443	    game->ai_death_reason = DEATH_NONE;
444	
445	    put_ai_snake_on_map(game);
446	
447	    // Ensure there are at least 2 food items on the map
448	    int food_count = 0;
449	    for (int r = 0; r < game->map_size; r++)
450	        for (int c = 0; c < game->map_size; c++)
451	            if (game->map[r][c] == 'F')
452	                food_count++;
453	    while (food_count < 2 && !game->game_over)
454	    {
455	        place_food(game);
456	        food_count++;
457	    }
458	}
