3	#include <stdlib.h>
4	
5	// Direction arrays matching game Direction enum order: UP, LEFT, DOWN, RIGHT
6	static const int AI_DR[4] = {-1, 0, 1, 0};
7	static const int AI_DC[4] = {0, -1, 0, 1};
8	static const Direction AI_DIR[4] = {UP, LEFT, DOWN, RIGHT};
9	
10	// BFS distance array
11	static int dist[MAX_MAP_SIZE][MAX_MAP_SIZE];
12	
13	// BFS queue
14	typedef struct node
15	{
16	    int r, c;
17	} Node;
18	static Node q[MAX_SNAKE_LEN];
19	
20	// ---------------------------------------------------------------------------
21	// Shared helpers
22	// ---------------------------------------------------------------------------
23	
24	// Check if a cell is passable for the AI (empty or food only)
25	static bool ai_can_go(const GameState *game, int r, int c)
26	{
27	    if (r <= 0 || r >= game->map_size - 1 || c <= 0 || c >= game->map_size - 1)
28	        return false;
29	    char ch = game->map[r][c];
30	    return (ch == '.' || ch == 'F');
31	}
32	
33	// BFS from food to compute distance grid
34	static void ai_bfs_from_food(const GameState *game, int fr, int fc)
35	{
36	    for (int r = 0; r < game->map_size; r++)
37	        for (int c = 0; c < game->map_size; c++)
38	            dist[r][c] = -1;
39	
40	    int front = 0, back = 0;
41	    q[back++] = {fr, fc};
42	    dist[fr][fc] = 0;
43	
44	    while (front < back)
45	    {
46	        Node cur = q[front++];
47	        for (int d = 0; d < 4; d++)
48	        {
49	            int nr = cur.r + AI_DR[d];
50	            int nc = cur.c + AI_DC[d];
51	            if (!ai_can_go(game, nr, nc))
52	                continue;
53	            if (dist[nr][nc] != -1)
54	                continue;
55	            dist[nr][nc] = dist[cur.r][cur.c] + 1;
56	            q[back++] = {nr, nc};
57	        }
58	    }
59	}
60	
61	// BFS to count free cells reachable from a starting point
62	static int ai_free_count(const GameState *game, int sr, int sc)
63	{
64	    int vis[MAX_MAP_SIZE][MAX_MAP_SIZE];
65	    memset(vis, 0, sizeof(vis));
66	
67	    Point queue[MAX_SNAKE_LEN];
68	    int front = 0, back = 0;
69	    queue[back++] = {sr, sc};
70	    vis[sr][sc] = 1;
71	    int cnt = 0;
72	
73	    while (front < back)
74	    {
75	        Point cur = queue[front++];
76	        cnt++;
77	        for (int d = 0; d < 4; d++)
78	        {
79	            int nr = cur.row + AI_DR[d];
80	            int nc = cur.col + AI_DC[d];
81	            if (nr <= 0 || nr >= game->map_size - 1 || nc <= 0 || nc >= game->map_size - 1)
82	                continue;
83	            if (vis[nr][nc])
84	                continue;
85	            char ch = game->map[nr][nc];
86	            if (ch != '.' && ch != 'F')
87	                continue;
88	            vis[nr][nc] = 1;
89	            queue[back++] = {nr, nc};
90	        }
91	    }
92	    return cnt;
93	}
94	
95	// BFS path finding on a simulated grid
96	static bool ai_bfs_path(char sim[MAX_MAP_SIZE][MAX_MAP_SIZE], int map_size,
97	                         int sr, int sc, int tr, int tc, int prev_dir[MAX_MAP_SIZE][MAX_MAP_SIZE])
98	{
99	    int vis[MAX_MAP_SIZE][MAX_MAP_SIZE];
100	    memset(vis, 0, sizeof(vis));
101	
102	    Point queue[MAX_SNAKE_LEN];
103	    int front = 0, back = 0;
104	    queue[back++] = {sr, sc};
105	    vis[sr][sc] = 1;
106	
107	    while (front < back)
108	    {
109	        Point cur = queue[front++];
110	        if (cur.row == tr && cur.col == tc)
111	            return true;
112	
113	        for (int d = 0; d < 4; d++)
114	        {
115	            int nr = cur.row + AI_DR[d];
116	            int nc = cur.col + AI_DC[d];
117	            if (nr <= 0 || nr >= map_size - 1 || nc <= 0 || nc >= map_size - 1)
118	                continue;
119	            if (vis[nr][nc])
120	                continue;
121	            if (nr == tr && nc == tc)
122	            {
123	                vis[nr][nc] = 1;
124	                prev_dir[nr][nc] = d;
125	                queue[back++] = {nr, nc};
126	                continue;
127	            }
128	            char ch = sim[nr][nc];
129	            if (ch != '.' && ch != 'F')
130	                continue;
131	            vis[nr][nc] = 1;
132	            prev_dir[nr][nc] = d;
133	            queue[back++] = {nr, nc};
134	        }
135	    }
136	    return false;
137	}
138	
139	// Check if AI can still reach its own tail after moving in direction d
140	static bool ai_can_reach_tail_after_move(const GameState *game, int d)
141	{
142	    const Point *body = game->ai_snake;
143	    int len = game->ai_length;
144	
145	    Point hd = body[0];
146	    Point tail = body[len - 1];
147	
148	    int nr = hd.row + AI_DR[d];
149	    int nc = hd.col + AI_DC[d];
150	
151	    char sim[MAX_MAP_SIZE][MAX_MAP_SIZE];
152	    for (int r = 0; r < game->map_size; r++)
153	        for (int c = 0; c < game->map_size; c++)
154	            sim[r][c] = game->map[r][c];
155	
156	    bool eat = (sim[nr][nc] == 'F');
157	    bool auto_grow = ((game->move_count + 1) % game->grow_step) == 0;
158	    bool will_grow = eat || auto_grow;
159	
160	    if (!will_grow)
161	        sim[tail.row][tail.col] = '.';
162	
163	    sim[hd.row][hd.col] = 'C';
164	    sim[nr][nc] = 'A';
165	
166	    int prev_dir[MAX_MAP_SIZE][MAX_MAP_SIZE];
167	    memset(prev_dir, -1, sizeof(prev_dir));
168	
169	    Point new_tail;
170	    if (will_grow)
171	        new_tail = tail;
172	    else
173	        new_tail = body[len - 2];
174	
175	    return ai_bfs_path(sim, game->map_size, nr, nc, new_tail.row, new_tail.col, prev_dir);
176	}
177	
178	// Collect all valid directions from the AI's current head position
179	static int collect_valid_dirs(const GameState *game, int *dirs_out)
180	{
181	    Point hd = game->ai_snake[0];
182	    int count = 0;
183	    for (int d = 0; d < 4; d++)
184	    {
185	        int nr = hd.row + AI_DR[d];
186	        int nc = hd.col + AI_DC[d];
187	        if (ai_can_go(game, nr, nc))
188	            dirs_out[count++] = d;
189	    }
190	    return count;
191	}
