```cpp
#include <iostream>
#include <string>
using namespace std;

struct Player {
    string name;
    int hp;
};

void damage(Player *p, int dmg) {
    p->hp -= dmg;
    if (p->hp < 0)
        p->hp = 0;
}

int main() {
    Player alice = {"Alice", 100};
    cout << alice.name << " before damage: HP = " << alice.hp << endl;

    damage(&alice, 30);
    cout << alice.name << " after damage: HP = " << alice.hp << endl;

    damage(&alice, 20);
    cout << alice.name << " after damage: HP = " << alice.hp << endl;

    damage(&alice, 999);
    cout << alice.name << " after damage: HP = " << alice.hp << endl;

    return 0;
}
