65	    int count = collect_empty_cells(game, cells);
66	    if (count <= 0)
67	    {
68	        game->game_over = true;
69	        game->death_reason = DEATH_FULL_MAP;
70	        return;
71	    }
72	    int idx = rand() % count;
73	    game->map[cells[idx].row][cells[idx].col] = 'F';
74	}
