76	// Generate random obstacles on empty cells.
77	// count: desired number (capped at 25% of available empty cells).
78	void generate_obstacles(GameState *game, int count)
79	{
80	    // Collect all empty interior cells
81	    Point cells[MAX_SNAKE_LEN];
82	    int total = 0;
83	    for (int r = 1; r < game->map_size - 1; r++)
84	        for (int c = 1; c < game->map_size - 1; c++)
85	            if (game->map[r][c] == '.')
86	            {
87	                cells[total].row = r;
88	                cells[total].col = c;
89	                total++;
90	            }
91	
92	    // Cap at 25% of empty cells to keep the map playable
93	    int max_obstacles = total / 4;
94	    if (count > max_obstacles)
95	        count = max_obstacles;
96	    if (count <= 0)
97	        return;
98	
99	    // Partial Fisher-Yates shuffle: randomly select 'count' cells
100	    for (int i = 0; i < count; i++)
101	    {
102	        int j = i + rand() % (total - i);
103	        game->map[cells[j].row][cells[j].col] = 'O';
104	        Point tmp = cells[i];
105	        cells[i] = cells[j];
106	        cells[j] = tmp;
107	    }
108	}
