198	static Point next_head(Point head, Direction dir)
199	{
200	    Point next = head;
201	    switch (dir)
202	    {
203	    case UP:
204	        next.row--;
205	        break;
206	    case DOWN:
207	        next.row++;
208	        break;
209	    case LEFT:
210	        next.col--;
211	        break;
212	    case RIGHT:
213	        next.col++;
214	        break;
215	    }
216	    return next;
217	}
