219	static bool can_enter_cell(GameState *game, Point next, bool will_grow,
220	                            const Point *body, int length, DeathReason *out_reason)
221	{
222	    char cell = game->map[next.row][next.col];
223	    Point tail = body[length - 1];
224	
225	    if (cell == '#')
226	    {
227	        if (out_reason) *out_reason = DEATH_WALL;
228	        return false;
229	    }
230	    if (cell == 'O')
231	    {
232	        if (out_reason) *out_reason = DEATH_OBSTACLE;
233	        return false;
234	    }
235	    // Player body characters
236	    if (cell == 'B')
237	    {
238	        if (!will_grow && is_same_point(next, tail))
239	            return true;
240	        if (out_reason) *out_reason = DEATH_BODY;
241	        return false;
242	    }
243	    // AI body characters
244	    if (cell == 'C')
245	    {
246	        if (!will_grow && is_same_point(next, tail))
247	            return true;
248	        if (out_reason) *out_reason = DEATH_ENEMY_BODY;
249	        return false;
250	    }
251	    // Opponent head
252	    if (cell == 'H' || cell == 'A')
253	    {
254	        if (out_reason) *out_reason = DEATH_HEAD_ON;
255	        return false;
256	    }
257	    return true;
258	}
