267	// Original move_snake for classic/obstacle modes
268	void move_snake(GameState *game)
269	{
270	    if (!game->started || game->paused || game->game_over)
271	        return;
272	
273	    Point old_head = game->snake[0];
274	    Point next = next_head(old_head, game->direction);
275	    bool will_eat = (game->map[next.row][next.col] == 'F');
276	    bool auto_grow = ((game->move_count + 1) % game->grow_step) == 0;
277	    bool will_grow = will_eat || auto_grow;
278	
279	    DeathReason reason = DEATH_NONE;
280	    if (!can_enter_cell(game, next, will_grow, game->snake, game->length, &reason))
281	    {
282	        game->game_over = true;
283	        game->death_reason = reason;
284	        return;
285	    }
286	
287	    // Remove tail
288	    if (!will_grow)
289	    {
290	        Point tail = game->snake[game->length - 1];
291	        game->map[tail.row][tail.col] = '.';
292	    }
293	    else if (game->length < MAX_SNAKE_LEN)
294	    {
295	        game->length++;
296	    }
297	
298	    // Old head becomes body
299	    game->map[old_head.row][old_head.col] = 'B';
300	
301	    // Shift body
302	    for (int i = game->length - 1; i > 0; i--)
303	        game->snake[i] = game->snake[i - 1];
304	    game->snake[0] = next;
305	    game->map[next.row][next.col] = 'H';
306	    game->move_count++;
307	
308	    if (will_eat)
309	    {
310	        game->score += 10;
311	        game->food_eaten++;
312	        place_food(game);
313	    }
314	
315	    game->turn_locked = false;
316	}
