337	// Apply a single snake move. Returns true if food was eaten.
338	static bool apply_snake_move(GameState *game, Point *body, int *length,
339	                              Direction dir, int *score, int *food_eaten,
340	                              int *pending_growth,
341	                              char head_char, char body_char)
342	{
343	    Point old_head = body[0];
344	    Point next = next_head(old_head, dir);
345	    bool will_eat = (game->map[next.row][next.col] == 'F');
346	    bool auto_grow = ((game->move_count + 1) % game->grow_step) == 0;
347	    bool has_pending = (*pending_growth > 0);
348	    bool effective_grow = will_eat || auto_grow || has_pending;
349	
350	    // Remove tail
351	    if (!effective_grow)
352	    {
353	        Point tail = body[*length - 1];
354	        game->map[tail.row][tail.col] = '.';
355	    }
356	    else if (*length < MAX_SNAKE_LEN)
357	    {
358	        (*length)++;
359	    }
360	
361	    // Consume one pending growth credit (only when not eating/auto-growing)
362	    if (has_pending && !will_eat && !auto_grow)
363	        (*pending_growth)--;
364	
365	    // Old head becomes body
366	    game->map[old_head.row][old_head.col] = body_char;
367	
368	    // Shift body
369	    for (int i = *length - 1; i > 0; i--)
370	        body[i] = body[i - 1];
371	    body[0] = next;
372	    game->map[next.row][next.col] = head_char;
373	
374	    if (will_eat)
375	    {
376	        *score += 10;
377	        (*food_eaten)++;
378	    }
379	
380	    return will_eat;
381	}
