790	// Move both snakes in PvP mode with collision resolution
791	void move_pvp_snakes(GameState *game)
792	{
793	    if (!game->started || game->paused || game->game_over)
794	        return;
795	
796	    Direction p1_dir = game->direction;
797	    Direction p2_dir = game->ai_direction;
798	
799	    // Compute next head positions
800	    Point p1_next = next_head(game->snake[0], p1_dir);
801	    Point p2_next = next_head(game->ai_snake[0], p2_dir);
802	
803	    // Check what's at each next cell
804	    char p1_cell = game->map[p1_next.row][p1_next.col];
805	    char p2_cell = game->map[p2_next.row][p2_next.col];
806	
807	    bool p1_will_eat = (p1_cell == 'F');
808	    bool p2_will_eat = (p2_cell == 'F');
809	    bool auto_grow = ((game->move_count + 1) % game->grow_step) == 0;
810	    bool p1_will_grow = p1_will_eat || auto_grow;
811	    bool p2_will_grow = p2_will_eat || auto_grow;
812	
813	    bool p1_dies = false;
814	    bool p2_dies = false;
815	    DeathReason p1_reason = DEATH_NONE;
816	    DeathReason p2_reason = DEATH_NONE;
817	    bool p1_grows_from_kill = false;
818	    bool p2_grows_from_kill = false;
819	    int p1_grow_amount = 0;
820	    int p2_grow_amount = 0;
821	
822	    // --- Collision Resolution ---
823	
824	    // 1. Head-on collision
825	    if (is_same_point(p1_next, p2_next))
826	    {
827	        p1_dies = true;
828	        p1_reason = DEATH_HEAD_ON;
829	        p2_dies = true;
830	        p2_reason = DEATH_HEAD_ON;
831	    }
832	    else
833	    {
834	        // 2. P1 head hits P2 body
835	        if (p1_cell == 'C')
836	        {
837	            if (!p2_will_grow && is_same_point(p1_next, game->ai_snake[game->ai_length - 1]))
838	            {
839	                // P1 can pass through P2's tail that's about to move
840	            }
841	            else
842	            {
843	                p1_dies = true;
844	                p1_reason = DEATH_ENEMY_BODY;
845	                p2_grows_from_kill = true;
846	                p2_grow_amount = game->length;
847	            }
848	        }
849	
850	        // 3. P2 head hits P1 body
851	        if (p2_cell == 'B')
852	        {
853	            if (!p1_will_grow && is_same_point(p2_next, game->snake[game->length - 1]))
854	            {
855	                // P2 can pass through P1's tail that's about to move
856	            }
857	            else
858	            {
859	                p2_dies = true;
860	                p2_reason = DEATH_ENEMY_BODY;
861	                p1_grows_from_kill = true;
862	                p1_grow_amount = game->ai_length;
863	            }
864	        }
865	
866	        // 4. P1 hits wall/obstacle
867	        if (p1_cell == '#' || p1_cell == 'O')
868	        {
869	            p1_dies = true;
870	            p1_reason = (p1_cell == '#') ? DEATH_WALL : DEATH_OBSTACLE;
871	        }
872	
873	        // 5. P2 hits wall/obstacle
874	        if (p2_cell == '#' || p2_cell == 'O')
875	        {
876	            p2_dies = true;
877	            p2_reason = (p2_cell == '#') ? DEATH_WALL : DEATH_OBSTACLE;
878	        }
879	
880	        // 6. P1 self-collision
881	        if (!p1_dies && p1_cell == 'B')
882	        {
883	            if (!p1_will_grow && is_same_point(p1_next, game->snake[game->length - 1]))
884	            {
885	                // safe — own tail
886	            }
887	            else
888	            {
889	                p1_dies = true;
890	                p1_reason = DEATH_BODY;
891	            }
892	        }
893	
894	        // 7. P2 self-collision
895	        if (!p2_dies && p2_cell == 'C')
896	        {
897	            if (!p2_will_grow && is_same_point(p2_next, game->ai_snake[game->ai_length - 1]))
898	            {
899	                // safe — own tail
900	            }
901	            else
902	            {
903	                p2_dies = true;
904	                p2_reason = DEATH_BODY;
905	            }
906	        }
907	    }
908	
909	    // --- Execute Results ---
910	
911	    // Handle P2 death — game over, P1 wins
912	    if (p2_dies)
913	    {
914	        clear_snake_from_map(game, game->ai_snake, game->ai_length, 'A', 'C');
915	        game->ai_is_alive = false;
916	        game->ai_death_reason = p2_reason;
917	        game->game_over = true;
918	
919	        if (p1_grows_from_kill && p1_grow_amount > 0)
920	        {
921	            add_pending_growth(&game->pending_growth, p1_grow_amount);
922	        }
923	
924	        // Apply P1's move one last time
925	        if (!p1_dies)
926	        {
927	            apply_snake_move(game, game->snake, &game->length,
928	                             p1_dir, &game->score, &game->food_eaten,
929	                             &game->pending_growth,
930	                             'H', 'B');
931	        }
932	
933	        game->move_count++;
934	        game->turn_locked = false;
935	        game->p2_turn_locked = false;
936	        return;
937	    }
938	
939	    // Handle P1 death — game over, P2 wins
940	    if (p1_dies)
941	    {
942	        game->death_reason = p1_reason;
943	        game->game_over = true;
944	
945	        if (p2_grows_from_kill && p2_grow_amount > 0)
946	        {
947	            add_pending_growth(&game->ai_pending_growth, p2_grow_amount);
948	        }
949	
950	        // Apply P2's move one last time
951	        if (!p2_dies && game->ai_is_alive)
952	        {
953	            apply_snake_move(game, game->ai_snake, &game->ai_length,
954	                             p2_dir, &game->ai_score, &game->ai_food_eaten,
955	                             &game->ai_pending_growth,
956	                             'A', 'C');
957	        }
958	
959	        game->move_count++;
960	        game->turn_locked = false;
961	        game->p2_turn_locked = false;
962	        return;
963	    }
964	
965	    // Apply P1 move
966	    {
967	        bool ate = apply_snake_move(game, game->snake, &game->length,
968	                                     p1_dir, &game->score, &game->food_eaten,
969	                                     &game->pending_growth,
970	                                     'H', 'B');
971	        if (ate)
972	            place_food(game);
973	    }
974	
975	    // Apply P2 move
976	    {
977	        bool ate = apply_snake_move(game, game->ai_snake, &game->ai_length,
978	                                     p2_dir, &game->ai_score, &game->ai_food_eaten,
979	                                     &game->ai_pending_growth,
980	                                     'A', 'C');
981	        if (ate)
982	            place_food(game);
983	    }
984	
985	    // Ensure at least 2 food items on the map
986	    {
987	        int food_count = 0;
988	        for (int r = 0; r < game->map_size; r++)
989	            for (int c = 0; c < game->map_size; c++)
990	                if (game->map[r][c] == 'F')
991	                    food_count++;
992	        while (food_count < 2 && !game->game_over)
993	        {
994	            place_food(game);
995	            food_count++;
996	        }
997	    }
998	
999	    game->move_count++;
1000	    game->turn_locked = false;
1001	    game->p2_turn_locked = false;
1002	}
