193	static Direction ai_dir_easy(const GameState *game)
194	{
195	    Point hd = game->ai_snake[0];
196	
197	    // 30% chance: pick a random valid direction
198	    if (rand() % 100 < 30)
199	    {
200	        int valid[4], cnt = collect_valid_dirs(game, valid);
201	        if (cnt > 0)
202	            return AI_DIR[valid[rand() % cnt]];
203	    }
204	
205	    // Find food and go toward it by Manhattan distance
206	    int fr = -1, fc = -1;
207	    for (int r = 0; r < game->map_size; r++)
208	        for (int c = 0; c < game->map_size; c++)
209	            if (game->map[r][c] == 'F')
210	            {
211	                fr = r;
212	                fc = c;
213	                goto food_found_easy;
214	            }
215	food_found_easy:
216	
217	    if (fr != -1)
218	    {
219	        int best_dir = -1, best_dist = 1000000;
220	        for (int d = 0; d < 4; d++)
221	        {
222	            int nr = hd.row + AI_DR[d];
223	            int nc = hd.col + AI_DC[d];
224	            if (!ai_can_go(game, nr, nc))
225	                continue;
226	            int mdist = abs(nr - fr) + abs(nc - fc);
227	            if (mdist < best_dist)
228	            {
229	                best_dist = mdist;
230	                best_dir = d;
231	            }
232	        }
233	        if (best_dir != -1)
234	            return AI_DIR[best_dir];
235	    }
236	
237	    // Fallback: most free space
238	    int best_dir = -1, best_space = -1;
239	    for (int d = 0; d < 4; d++)
240	    {
241	        int nr = hd.row + AI_DR[d];
242	        int nc = hd.col + AI_DC[d];
243	        if (!ai_can_go(game, nr, nc))
244	            continue;
245	        int space = ai_free_count(game, nr, nc);
246	        if (space > best_space)
247	        {
248	            best_space = space;
249	            best_dir = d;
250	        }
251	    }
252	    if (best_dir != -1)
253	        return AI_DIR[best_dir];
254	
255	    // Last resort
256	    for (int d = 0; d < 4; d++)
257	    {
258	        int nr = hd.row + AI_DR[d];
259	        int nc = hd.col + AI_DC[d];
260	        if (ai_can_go(game, nr, nc))
261	            return AI_DIR[d];
262	    }
263	    return game->ai_direction;
264	}
