348	static Direction ai_dir_hard(const GameState *game)
349	{
350	    const Point *body = game->ai_snake;
351	    Point hd = body[0];
352	
353	    int fr = -1, fc = -1;
354	    for (int r = 0; r < game->map_size; r++)
355	        for (int c = 0; c < game->map_size; c++)
356	            if (game->map[r][c] == 'F')
357	            {
358	                fr = r;
359	                fc = c;
360	                goto food_found_hard;
361	            }
362	food_found_hard:
363	
364	    int best_dir = -1;
365	
366	    if (fr != -1)
367	    {
368	        int best_dist = 1000000;
369	        ai_bfs_from_food(game, fr, fc);
370	
371	        for (int d = 0; d < 4; d++)
372	        {
373	            int nr = hd.row + AI_DR[d];
374	            int nc = hd.col + AI_DC[d];
375	            if (!ai_can_go(game, nr, nc))
376	                continue;
377	            if (dist[nr][nc] == -1)
378	                continue;
379	
380	            // Early game: greedy
381	            if (game->ai_length < 105)
382	            {
383	                if (dist[nr][nc] < best_dist)
384	                {
385	                    best_dist = dist[nr][nc];
386	                    best_dir = d;
387	                }
388	            }
389	            else
390	            {
391	                // Late game: safety check
392	                if (!ai_can_reach_tail_after_move(game, d))
393	                    continue;
394	                if (dist[nr][nc] < best_dist)
395	                {
396	                    best_dist = dist[nr][nc];
397	                    best_dir = d;
398	                }
399	            }
400	        }
401	
402	        if (best_dir != -1)
403	            return AI_DIR[best_dir];
404	    }
405	
406	    // Fallback: most free space
407	    int best_space = -1;
408	    for (int d = 0; d < 4; d++)
409	    {
410	        int nr = hd.row + AI_DR[d];
411	        int nc = hd.col + AI_DC[d];
412	        if (!ai_can_go(game, nr, nc))
413	            continue;
414	        int space = ai_free_count(game, nr, nc);
415	        if (space > best_space)
416	        {
417	            best_space = space;
418	            best_dir = d;
419	        }
420	    }
421	    if (best_dir != -1)
422	        return AI_DIR[best_dir];
423	
424	    // Last resort
425	    for (int d = 0; d < 4; d++)
426	    {
427	        int nr = hd.row + AI_DR[d];
428	        int nc = hd.col + AI_DC[d];
429	        if (ai_can_go(game, nr, nc))
430	            return AI_DIR[d];
431	    }
432	    return game->ai_direction;
433	}
