260	bool can_start_in_direction(GameState *game, Direction dir)
261	{
262	    Point next = next_head(game->snake[0], dir);
263	    DeathReason dummy = DEATH_NONE;
264	    return can_enter_cell(game, next, false, game->snake, game->length, &dummy);
265	}
