324	// Remove a snake's body cells from the map
325	static void clear_snake_from_map(GameState *game, const Point *body, int length,
326	                                  char head_char, char body_char)
327	{
328	    for (int i = 0; i < length; i++)
329	    {
330	        Point p = body[i];
331	        char ch = game->map[p.row][p.col];
332	        if (ch == head_char || ch == body_char)
333	            game->map[p.row][p.col] = '.';
334	    }
335	}
