460	// Move both snakes in battle mode with collision resolution
461	void move_battle_snakes(GameState *game)
462	{
463	    if (!game->started || game->paused || game->game_over)
464	        return;
465	
466	    // Compute AI direction
467	    Direction ai_dir = ai_choose_direction(game, game->ai_difficulty);
468	    game->ai_direction = ai_dir;
469	
470	    // Compute next head positions
471	    Point player_next = next_head(game->snake[0], game->direction);
472	    Point ai_next = next_head(game->ai_snake[0], ai_dir);
473	
474	    // Check what's at each next cell
475	    char player_cell = game->map[player_next.row][player_next.col];
476	    char ai_cell = game->map[ai_next.row][ai_next.col];
477	
478	    bool player_will_eat = (player_cell == 'F');
479	    bool ai_will_eat = (ai_cell == 'F');
480	    bool auto_grow = ((game->move_count + 1) % game->grow_step) == 0;
481	    bool player_will_grow = player_will_eat || auto_grow;
482	    bool ai_will_grow = ai_will_eat || auto_grow;
483	
484	    bool player_dies = false;
485	    bool ai_dies = false;
486	    DeathReason player_reason = DEATH_NONE;
487	    DeathReason ai_reason = DEATH_NONE;
488	    bool player_grows_from_kill = false;
489	    bool ai_grows_from_kill = false;
490	    int player_grow_amount = 0;
491	    int ai_grow_amount = 0;
492	
493	    // --- Collision Resolution ---
494	
495	    // 1. Head-on collision
496	    if (is_same_point(player_next, ai_next))
497	    {
498	        player_dies = true;
499	        player_reason = DEATH_HEAD_ON;
500	        ai_dies = true;
501	        ai_reason = DEATH_HEAD_ON;
502	    }
503	    else
504	    {
505	        // 2. Player head hits AI body
506	        if (player_cell == 'C')
507	        {
508	            // Check if AI is not growing and this is AI's tail — then it's safe
509	            if (!ai_will_grow && is_same_point(player_next, game->ai_snake[game->ai_length - 1]))
510	            {
511	                // Player can pass through AI's tail that's about to move
512	            }
513	            else
514	            {
515	                player_dies = true;
516	                player_reason = DEATH_ENEMY_BODY;
517	                ai_grows_from_kill = true;
518	                ai_grow_amount = game->length;
519	            }
520	        }
521	
522	        // 3. AI head hits player body
523	        if (ai_cell == 'B')
524	        {
525	            if (!player_will_grow && is_same_point(ai_next, game->snake[game->length - 1]))
526	            {
527	                // AI can pass through player's tail that's about to move
528	            }
529	            else
530	            {
531	                ai_dies = true;
532	                ai_reason = DEATH_ENEMY_BODY;
533	                player_grows_from_kill = true;
534	                player_grow_amount = game->ai_length;
535	            }
536	        }
537	
538	        // 4. Player hits wall/obstacle
539	        if (player_cell == '#' || player_cell == 'O')
540	        {
541	            player_dies = true;
542	            player_reason = (player_cell == '#') ? DEATH_WALL : DEATH_OBSTACLE;
543	        }
544	
545	        // 5. AI hits wall/obstacle
546	        if (ai_cell == '#' || ai_cell == 'O')
547	        {
548	            ai_dies = true;
549	            ai_reason = (ai_cell == '#') ? DEATH_WALL : DEATH_OBSTACLE;
550	        }
551	
552	        // 6. Player self-collision
553	        if (!player_dies && player_cell == 'B')
554	        {
555	            if (!player_will_grow && is_same_point(player_next, game->snake[game->length - 1]))
556	            {
557	                // safe — own tail
558	            }
559	            else
560	            {
561	                player_dies = true;
562	                player_reason = DEATH_BODY;
563	            }
564	        }
565	
566	        // 7. AI self-collision
567	        if (!ai_dies && ai_cell == 'C')
568	        {
569	            if (!ai_will_grow && is_same_point(ai_next, game->ai_snake[game->ai_length - 1]))
570	            {
571	                // safe — own tail
572	            }
573	            else
574	            {
575	                ai_dies = true;
576	                ai_reason = DEATH_BODY;
577	            }
578	        }
579	
580	        // 8. Player hits AI body tail (already handled in case 2)
581	    }
582	
583	    // --- Execute Results ---
584	
585	    // Handle AI death — player grows
586	    if (ai_dies)
587	    {
588	        clear_snake_from_map(game, game->ai_snake, game->ai_length, 'A', 'C');
589	        game->ai_is_alive = false;
590	        game->ai_death_reason = ai_reason;
591	
592	        if (player_grows_from_kill && player_grow_amount > 0)
593	        {
594	            add_pending_growth(&game->pending_growth, player_grow_amount);
595	        }
596	    }
597	
598	    // Handle player death
599	    if (player_dies)
600	    {
601	        game->death_reason = player_reason;
602	        game->game_over = true;
603	
604	        if (ai_grows_from_kill && ai_grow_amount > 0)
605	        {
606	            add_pending_growth(&game->ai_pending_growth, ai_grow_amount);
607	        }
608	
609	        // If AI is still alive, apply its move too (it gets the cell)
610	        if (!ai_dies && game->ai_is_alive)
611	        {
612	            int ate = apply_snake_move(game, game->ai_snake, &game->ai_length,
613	                                        ai_dir, &game->ai_score, &game->ai_food_eaten,
614	                                        &game->ai_pending_growth,
615	                                        'A', 'C');
616	            if (ate)
617	            {
618	                place_food(game);
619	                // Ensure at least 2 food items
620	                int fc = 1; // one just placed, check for more
621	                for (int r = 0; r < game->map_size; r++)
622	                    for (int c = 0; c < game->map_size; c++)
623	                        if (game->map[r][c] == 'F')
624	                            fc++;
625	                (void)fc; // food was placed, AI may have eaten one
626	            }
627	        }
628	
629	        game->move_count++;
630	        game->turn_locked = false;
631	        return;
632	    }
633	
634	    // Apply player move
635	    if (!player_dies)
636	    {
637	        bool ate = apply_snake_move(game, game->snake, &game->length,
638	                                     game->direction, &game->score, &game->food_eaten,
639	                                     &game->pending_growth,
640	                                     'H', 'B');
641	        if (ate)
642	            place_food(game);
643	    }
644	
645	    // Apply AI move
646	    if (!ai_dies && game->ai_is_alive)
647	    {
648	        bool ate = apply_snake_move(game, game->ai_snake, &game->ai_length,
649	                                     ai_dir, &game->ai_score, &game->ai_food_eaten,
650	                                     &game->ai_pending_growth,
651	                                     'A', 'C');
652	        if (ate)
653	            place_food(game);
654	    }
655	
656	    // Ensure at least 2 food items on the map in battle mode
657	    if (!game->game_over)
658	    {
659	        int food_count = 0;
660	        for (int r = 0; r < game->map_size; r++)
661	            for (int c = 0; c < game->map_size; c++)
662	                if (game->map[r][c] == 'F')
663	                    food_count++;
664	        while (food_count < 2 && !game->game_over)
665	        {
666	            place_food(game);
667	            food_count++;
668	        }
669	    }
670	
671	    // Respawn AI if it died
672	    if (ai_dies)
673	    {
674	        respawn_ai(game);
675	    }
676	
677	    game->move_count++;
678	    game->turn_locked = false;
679	}
