63	// --- PlayScene ---
64	void PlayScene::update()
65	{
66	    // Handle input
67	    if (key_pressed(VK_ESCAPE))
68	    {
69	        _next = SCENE_MENU;
70	        return;
71	    }
72	    if (key_pressed('R'))
73	    {
74	        restart_game();
75	        return;
76	    }
77	    if (key_pressed(VK_SPACE) && _game.started && !_game.game_over)
78	        _game.paused = !_game.paused;
79	    if (!_game.game_over)
80	    {
81	        // Player 1: WASD
82	        if (key_pressed('W'))
83	            set_direction(&_game, UP);
84	        else if (key_pressed('S'))
85	            set_direction(&_game, DOWN);
86	        else if (key_pressed('A'))
87	            set_direction(&_game, LEFT);
88	        else if (key_pressed('D'))
89	            set_direction(&_game, RIGHT);
90	
91	        // Player 2 (PvP only): Arrow keys
92	        if (_game.mode == MODE_PVP && _game.ai_is_alive)
93	        {
94	            if (key_pressed(VK_UP))
95	                set_p2_direction(&_game, UP);
96	            else if (key_pressed(VK_DOWN))
97	                set_p2_direction(&_game, DOWN);
98	            else if (key_pressed(VK_LEFT))
99	                set_p2_direction(&_game, LEFT);
100	            else if (key_pressed(VK_RIGHT))
101	                set_p2_direction(&_game, RIGHT);
102	        }
103	    }
104	
105	    // Timed movement with speed-up support
106	    DWORD now = GetTickCount();
107	    DWORD interval = MOVE_INTERVAL_MS;
108	
109	    // Speed-up: hold Shift or F to accelerate
110	    if (key_held(VK_SHIFT) || key_held('F'))
111	        interval = MOVE_INTERVAL_MS / 4;  // 40ms = 4x speed
112	
113	    if (now - _last_move >= interval)
114	    {
115	        if (_game.mode == MODE_PVP && !_game.game_over)
116	            move_pvp_snakes(&_game);
117	        else if (_game.mode == MODE_BATTLE && !_game.game_over)
118	            move_battle_snakes(&_game);
119	        else
120	            move_snake(&_game);
121	        _last_move = now;
122	    }
123	}
124	void PlayScene::render()
125	{
126	    draw_game(&_game);
127	}
