266	static Direction ai_dir_normal(const GameState *game)
267	{
268	    Point hd = game->ai_snake[0];
269	
270	    int fr = -1, fc = -1;
271	    for (int r = 0; r < game->map_size; r++)
272	        for (int c = 0; c < game->map_size; c++)
273	            if (game->map[r][c] == 'F')
274	            {
275	                fr = r;
276	                fc = c;
277	                goto food_found_normal;
278	            }
279	food_found_normal:
280	
281	    int best_dir = -1;
282	
283	    if (fr != -1)
284	    {
285	        int best_dist = 1000000;
286	        ai_bfs_from_food(game, fr, fc);
287	
288	        for (int d = 0; d < 4; d++)
289	        {
290	            int nr = hd.row + AI_DR[d];
291	            int nc = hd.col + AI_DC[d];
292	            if (!ai_can_go(game, nr, nc))
293	                continue;
294	            if (dist[nr][nc] == -1)
295	                continue;
296	
297	            // Normal difficulty: no tail-reachability safety check at any length
298	
299	            if (dist[nr][nc] < best_dist)
300	            {
301	                best_dist = dist[nr][nc];
302	                best_dir = d;
303	            }
304	        }
305	
306	        if (best_dir != -1)
307	        {
308	            // 15% chance: override with a random valid move
309	            if (rand() % 100 < 15)
310	            {
311	                int valid[4], cnt = collect_valid_dirs(game, valid);
312	                if (cnt > 0)
313	                    return AI_DIR[valid[rand() % cnt]];
314	            }
315	            return AI_DIR[best_dir];
316	        }
317	    }
318	
319	    // Fallback: most free space
320	    int best_space = -1;
321	    for (int d = 0; d < 4; d++)
322	    {
323	        int nr = hd.row + AI_DR[d];
324	        int nc = hd.col + AI_DC[d];
325	        if (!ai_can_go(game, nr, nc))
326	            continue;
327	        int space = ai_free_count(game, nr, nc);
328	        if (space > best_space)
329	        {
330	            best_space = space;
331	            best_dir = d;
332	        }
333	    }
334	    if (best_dir != -1)
335	        return AI_DIR[best_dir];
336	
337	    // Last resort
338	    for (int d = 0; d < 4; d++)
339	    {
340	        int nr = hd.row + AI_DR[d];
341	        int nc = hd.col + AI_DC[d];
342	        if (ai_can_go(game, nr, nc))
343	            return AI_DIR[d];
344	    }
345	    return game->ai_direction;
346	}
