438	Direction ai_choose_direction(const GameState *game, AIDifficulty difficulty)
439	{
440	    switch (difficulty)
441	    {
442	    case AI_EASY:
443	        return ai_dir_easy(game);
444	    case AI_NORMAL:
445	        return ai_dir_normal(game);
446	    case AI_HARD:
447	    default:
448	        return ai_dir_hard(game);
449	    }
450	}
